INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '真不愧是中国首批5星酒店之一，房间非常舒适，服务一流！虽然中间出了点小插曲，但是', '真不愧是中国首批5星酒店之一，房间非常舒适，服务一流！虽然中间出了点小插曲，但是非常及时和妥善的处理，令我感受到这酒店对客人那贴心的照顾。', '2024-01-04', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236x224x8tov0vzcAB94_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02350224x8tov6qxg7CC2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230c224x8tov307r7D17_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236a224x8tov4k991849_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02348224x8tov5tge6281_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f224x8tov5x4w48C3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j224x8touz97q9044_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02341224x8touz97r45B1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f224x8tov2lqpA209_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很不错，地理位置很方便，前台小姐姐帮忙升级了房间，有幸感受到了套房的舒适感，', '房间很不错，地理位置很方便，前台小姐姐帮忙升级了房间，有幸感受到了套房的舒适感，博物馆讲述了酒店的发展史', '2024-02-08', 5, '[''房间设施'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230e12000d5qn8scEE0D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000d5qqhk22C91_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000d5qmyauA834_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很小，床太软，睡的腰疼，', '房间很小，床太软，睡的腰疼，
早餐是中西合璧，对于中国胃来说能吃的不多
大堂和瀑布花园比较漂亮，房间就一般', '2024-02-05', 3, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234512000d4v0rlx0172_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间整体很不错，圣诞节装扮很漂亮。订的红棉大床，升级了粤韵大床。入住送了两只康乃', '房间整体很不错，圣诞节装扮很漂亮。订的红棉大床，升级了粤韵大床。入住送了两只康乃馨。早餐好吃，瀑布餐厅漂亮。买了纪念品给家人和孩子。除了一楼大厅香味过浓，床太软，其他都挺好。', '2023-12-14', 5, '[''整体满意度'', ''餐饮设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235q12000cqggj5k4758_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233812000cqgfo21B2B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000cqgffs30305_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000cqggjesBEB1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000cqgg919B0A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000cqggpxbF60B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000cqgglhj3AF2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很棒的酒店，下次还会再来，感谢前台接待的全体服务员，每天都来麻烦你们，都给我耐心', '很棒的酒店，下次还会再来，感谢前台接待的全体服务员，每天都来麻烦你们，都给我耐心解答，酒店还有打卡地图，送的礼品我老婆个孩子都喜欢', '2024-01-17', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235112000cyhulkjA49E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000cyhvdu17B37_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000cyhv448D482_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '交通方便，门口5号线淘金站，右转有点都德，服务很好，帮助拿放行李，卫生很好！对面', '交通方便，门口5号线淘金站，右转有点都德，服务很好，帮助拿放行李，卫生很好！对面有商场，非常方便！强烈推荐！', '2024-02-04', 5, '[''交通便利性'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232q12000d4hibzdD554_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236l12000d4hmivd0604_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000d4hv56u525B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间整洁，无论是一楼服务员还是楼成电梯员服务都很贴心。桃园馆菜品精致美味，同行的', '房间整洁，无论是一楼服务员还是楼成电梯员服务都很贴心。桃园馆菜品精致美味，同行的朋友和宝贝都很开心??。特别是行政酒廊Carrie，Sumny,Mia服务很贴心，感恩', '2023-12-23', 5, '[''客房服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232512000csaw7l8C0DD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000csasx7f9779_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间还算干净整洁，床???睡着也舒服，后花园晚上也很漂亮，总体感觉还不错。这次带', '房间还算干净整洁，床???睡着也舒服，后花园晚上也很漂亮，总体感觉还不错。这次带孩子一起来旅游，孩子爱上了后花园的大鲤鱼??', '2024-01-25', 5, '[''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233t12000d16uygl2D8C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000d16zlqzB69F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000d16y12j0F69_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大厅好豪气哦，喜庆得不得了。生日去的还送了个小蛋糕，2人吃吃正好。房间不大，还行', '大厅好豪气哦，喜庆得不得了。生日去的还送了个小蛋糕，2人吃吃正好。房间不大，还行吧。酒店的欢乐时光都来不及品尝，因为广州美食太多啦。', '2024-02-21', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233k12000d9d8trfAD75_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000d9d8lua0D8F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000d9d91wkCACC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星酒店确实不错，服务细节都很不错，推荐', '老牌五星酒店确实不错，服务细节都很不错，推荐', '2024-04-29', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232612000dtnvylx7621_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000dtnv15hEC36_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000dtnvhwy139E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000dtnw1of0348_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '对于1??座已经营业几十年的酒店，又是在市中心的老酒店来说，服务绝对满意??', '对于1??座已经营业几十年的酒店，又是在市中心的老酒店来说，服务绝对满意??', '2024-03-04', 4, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233k12000dc6pimeFAF3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务态度很好，外国人比较多，春节的气氛很浓厚。餐厅早餐有人引导，值得??，要是食', '服务态度很好，外国人比较多，春节的气氛很浓厚。餐厅早餐有人引导，值得??，要是食物再丰富一点就更好了。', '2024-02-10', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235l12000d68eo5r1EFD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000d68cp3y40B1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常感谢酒店的服务，不愧于超五星级酒店，很漂亮，特别我有衣物遗留在房间，也顺利找', '非常感谢酒店的服务，不愧于超五星级酒店，很漂亮，特别我有衣物遗留在房间，也顺利找回。一直忙没有评论，再次感谢??', '2024-02-20', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233o12000d94zpdi2917_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000d958ua33874_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000d95anbh9E94_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000d95aveqCA21_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000d95865pAC38_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间比较干净，环境很好，设施比较齐全，服务态度非常好', '房间比较干净，环境很好，设施比较齐全，服务态度非常好', '2024-03-25', 5, '[''卫生状况'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235412000dhyhjfx7BA7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000dhyi7f7ED70_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000dhyhjg157B3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '上年中秋来攞月饼就觉得好靓，今次终于有机会来住几日好开心。不愧系老字号酒店，装修', '上年中秋来攞月饼就觉得好靓，今次终于有机会来住几日好开心。不愧系老字号酒店，装修风格特别有香港新加波D feel，出去逛圈成条环市东路都好有历史沉淀。花花草草同埋锦鲤都好靓，仲喺花店看到蓝Vanda。服务亦都唔错，话间房出边好吵就即刻同我换左去楼上。至于餐饮，食左酒店入边间日本料理同早餐只能够话无功无过，最开心系去对面友谊商店大快活食个咖喱鸡扒，隔离台个细路仔一直bie住我，仲攞支手枪biubiu下，哈哈见到佢地两仔爷钩起塞我d童年回忆，我细个时同老豆都系咁一起去食大快活，宜家霖起真系感概万千啊。', '2023-11-12', 4, '[''整体满意度'', ''安静程度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0233t2215gzzly9q84F3D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p2234d6py47hcB231_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k2224x3cs1o1c970A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i2224x3csso9d248C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c2234d6pz05681069_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/023152215gzzmv2a8FF98_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235p2224x3csy15s86F4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a2234d6pz17r4AF88_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t2215gzznbzuo513C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '走进酒店大堂就看见一个超大的漂亮圣诞??，即刻让人产生喜悦的心情。办理入住的客服', '走进酒店大堂就看见一个超大的漂亮圣诞??，即刻让人产生喜悦的心情。办理入住的客服经理非常耐心热情还送了欢迎入住的康乃馨。酒店房间很大，干净整洁。瀑布餐厅的自助早餐管理有序环境好，酒店的地理位置优越，出门散步享受美味都很方便，入住体验非常好', '2023-12-08', 5, '[''整体满意度'', ''前台服务'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0235a12000cp9cplm3787_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000cp9b6u35D25_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000cp9cl6mA62F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000cp9dwoy712C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次入住花园酒店，进门第一感觉就很吃惊，环境，服务都很好，荔湾亭早茶味道很棒，', '第一次入住花园酒店，进门第一感觉就很吃惊，环境，服务都很好，荔湾亭早茶味道很棒，小朋友对蛋挞赞不绝口，下次来会继续选择', '2024-01-24', 5, '[''餐饮设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235y12000d110rqr174C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000d10ryecD2EE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000d10ukcu81E6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000d118slzF64D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l12000d10yvvlBE97_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000d114b4c56D5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000d10uwi07A44_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为一名花园酒店三十年前的老员工，对花园有一种说不出的情感 这里是我梦想开始的地', '作为一名花园酒店三十年前的老员工，对花园有一种说不出的情感 这里是我梦想开始的地方，打开了我认识世界的第一道大门，那时候就觉得自己工作在这样豪华的酒店很不真实，丰富而美味的员工餐让我每天工作心情愉快，现在成为酒店的客人，从另一个角度用更成熟的心智带着更饱满的酒店业认知更加体会到酒店业的传承和花园的经久不衰，的确有它的无可代替的魅力，房间升级了，床品非常讲究，让每一个客人都拥有好的睡眠，隔音效果非常好，这也是与其它新酒店不同之处，以前的酒店建造真的真材实料。米其林餐厅各个出品精湛，口感和卖相都精益求精。酒店入住客人很多，但也稳中不乱。花园小径深处，流水潺潺，锦鲤酒店，锦鲤人生。感谢花园。', '2023-10-31', 5, '[''整体满意度'', ''房间设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234s12000chhi8e004FE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230512000chhmgnz6616_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000chhmmjc954D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e12000chhlzis57B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000chhii9r2548_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000chhj0pc4946_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231l12000chhj6100EF3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000chhl0oh07CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234o12000chhi8je5844_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务周到，酒店各处都洋溢着节日气氛，后花园景色很美！环境不错，工作人员服务热', '酒店服务周到，酒店各处都洋溢着节日气氛，后花园景色很美！环境不错，工作人员服务热情，一次很好的入住体验！', '2024-02-11', 5, '[''整体满意度'', ''前台服务'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0234f12000d6bb6r35677_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000d6bboanC65E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000d6b8jmj1027_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000d6bay1o52CF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000d6bbkgt43EF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233112000d6b8u8h7BA0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间翻新过，房间很新，服务很好，老牌底蕴，早餐很丰富有瀑布餐厅和30楼酒廊旋转餐', '房间翻新过，房间很新，服务很好，老牌底蕴，早餐很丰富有瀑布餐厅和30楼酒廊旋转餐厅，由于之前单间房间面积比较小，红棉双床房是两张1.1米的单人床带浴缸，最新翻新的粤韵双床房是1.3米的单人床，就没有浴缸空间了，粤韵大床房带浴缸。冬季泳池旁开了恒温按摩浴缸。酒店内有多家餐厅，这次在荔湾亭用餐，出品很棒！', '2023-11-23', 5, '[''房间设施'', ''餐饮设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0201r12000cmia0ey8C19_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0206r12000cmia57dC07E_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0235q12000cmhzsdsE7AD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230o12000cmi3blxAB7B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000cmi3f12EDFB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000cmi43b6C2B6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '从服务到房间都很满意。酒店的装潢我定义为中式摩登，古典和现代相容并立，沉稳且桀骜', '从服务到房间都很满意。酒店的装潢我定义为中式摩登，古典和现代相容并立，沉稳且桀骜，优雅且时尚。下次还会再来', '2024-02-03', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230v12000d49pbj3D3D1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一如既往的喜欢，虽然是老牌的酒店，管理很到位，服务很好，早餐也很丰盛', '一如既往的喜欢，虽然是老牌的酒店，管理很到位，服务很好，早餐也很丰盛', '2024-03-19', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231g12000dg93dks5DC4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000dg9jt2zB2BE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店外观很大气，很漂亮，房间都挺好的，干净清静，就是比较小，洗漱台也比较狭窄，卫', '酒店外观很大气，很漂亮，房间都挺好的，干净清静，就是比较小，洗漱台也比较狭窄，卫生间的门和洗澡的门不能同时关上，这点不太方便！酒店的甜品很不错，有点小贵，早餐要早点去，人多会需要排队！', '2023-12-05', 5, '[''房间设施'', ''卫生状况'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235k12000colj5dz479A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000colpojeC9FA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000colf7nz7341_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住体验不错。酒店大堂富丽堂皇，很气派，办理入住手续快捷，前台美女安排了一间相对', '入住体验不错。酒店大堂富丽堂皇，很气派，办理入住手续快捷，前台美女安排了一间相对安静的房间，如果酒店外围没施工入住体验会更好。房间布局合理设计风格很喜欢，有小会客室，看电视和房间休息互不干扰。最赞的就是酒店的服务质量，只要在公共区域停留或者疑惑的瞬间，都会有服务员询问是否需要帮助。不管是早餐还是午餐等服务接待都很彬彬有礼，温文尔雅，让人感到心情愉悦，以后到广州就首选花园酒店！', '2023-11-24', 5, '[''整体满意度'', ''前台服务'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230s12000cmp8mxuF12C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000cmp9v4xC9E8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000cmpagy38C5B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住酒店时出乎意料地给我们升级成了套房，酒店服务很好，酒店的景致真是出乎意料的美', '入住酒店时出乎意料地给我们升级成了套房，酒店服务很好，酒店的景致真是出乎意料的美丽，岭南风格的绿植及壁画互相映衬，市中心的酒店能有这么大的花园真的不容易。我们还参观了酒店博物馆。看到了酒店的发展史。下次去广州还想住这里', '2023-11-22', 5, '[''整体满意度'', ''景观/朝向'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232e12000cmao2j31B0C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000cmatzyz156E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000cmans9p14C4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店有文化沉淀，有独到设计，有中西交融，有优质服务，将花园特色融入每个角落，漂亮', '酒店有文化沉淀，有独到设计，有中西交融，有优质服务，将花园特色融入每个角落，漂亮大气。值得一提的是服务人员都热情、礼貌、细心，前台靓女Gillian还在房间紧张的情况下，帮我解决了续住问题，非常感谢！', '2023-11-09', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232k12000cjk2t5g699A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i12000cjk53xs5990_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000cjk85v0EF5D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000cjkdi6e743B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000cjk7nq0FE51_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000cjkftpr9CD5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000cjk78jlF854_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000cjkfvoy6A19_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000cjk6z4n8199_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店工作人员态度都非常好，尤其是前台小哥哥还帮忙升级了房型，孩子来广州参加比赛，', '酒店工作人员态度都非常好，尤其是前台小哥哥还帮忙升级了房型，孩子来广州参加比赛，休息的很好。酒店博物馆及小花园印象深刻。此次入住超值，下次来广州还会选择花园酒店。', '2023-12-18', 5, '[''前台服务'', ''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0234k12000cr42x3pF132_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000cr3xkpz4596_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大厅很气派，老牌酒店，卫生很好，周边热闹，吃饭什么都方便。离地铁站也近，地铁站就', '大厅很气派，老牌酒店，卫生很好，周边热闹，吃饭什么都方便。离地铁站也近，地铁站就在酒店门口。有机会还会选择入住', '2024-02-03', 5, '[''交通便利性'', ''周边配套'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230912000d457ahaC733_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000d454drk57D6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000d457ejh205E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000d456favA43B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店看起来很大气，savanna小姐姐的服务超级好，长的很漂亮，也很可爱！太感谢', '酒店看起来很大气，savanna小姐姐的服务超级好，长的很漂亮，也很可爱！太感谢savanna小姐姐了。下次入住还是找她帮忙办理！房间也很棒，装修等等也很有特色！抱着尝试的心态入住，没想到爱上了，又多住了几天！下次还一定来！', '2023-11-28', 5, '[''前台服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236v12000cneo36tA742_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000cneiewn349F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000cneiafsEFA2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务质量很高的一家老牌酒店。早餐很不错，瀑布餐厅很棒。床和枕头很舒服。恰逢周一，', '服务质量很高的一家老牌酒店。早餐很不错，瀑布餐厅很棒。床和枕头很舒服。恰逢周一，可惜这次没看到花园博物馆。', '2024-01-29', 5, '[''餐饮设施'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235l12000d2o6s6tD29B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000d2o041k6FD0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000d2nurpq156A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店确实有点年代了，不过也恰好看到当年的情怀，红棉房感觉装修有点久远，设施一般般', '酒店确实有点年代了，不过也恰好看到当年的情怀，红棉房感觉装修有点久远，设施一般般吧，位置确实很不错。也感谢酒店送了生日蛋糕，早餐环境很好（座位一般、人比较多要排队），总体说是不错的体验，性价比不算太好，不过老广东的过来住一下还是挺值得的。', '2023-11-19', 4, '[''性价比'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231112000cllxpb4D4A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000cllxadwEB96_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000cllxqw4AAF9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000clly5vr5790_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000clluxnj44DC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000cllxpb65F32_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务员很热情??春节大堂的活动气氛到位了，酒店位置确认很方便。房间翻新了，面积不', '服务员很热情??春节大堂的活动气氛到位了，酒店位置确认很方便。房间翻新了，面积不大也够住。', '2024-02-17', 5, '[''前台服务'', ''交通便利性'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231v12000d88gl7xD610_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台汪莹莹服务态度很好，是很好的一次体验', '前台汪莹莹服务态度很好，是很好的一次体验', '2024-04-19', 4, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232n12000dq56cje7568_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌广州豪华酒店，基本每次来都住这。房间设施齐全，工作人员服务也很nice,二楼', '老牌广州豪华酒店，基本每次来都住这。房间设施齐全，工作人员服务也很nice,二楼的粤式早茶百吃不厌，强烈推荐的一家酒店！', '2024-01-19', 5, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231f12000cz9d5pjB250_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000cz9l6sx42B0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间非常干净整洁，设施齐全，不愧老牌白金五星酒店，底蕴深厚。', '房间非常干净整洁，设施齐全，不愧老牌白金五星酒店，底蕴深厚。
花园打理的也非常好，花草树木、池塘锦鲤一看就是有专人养护的。', '2024-01-17', 5, '[''卫生状况'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231f12000cyl0ua80923_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000cyl0uhi4E36_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000cyl0uhmF95C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000cyl0uhoFEB9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000cyl0uhs7ABF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000cyl0uit61B4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '在花园连住四晚，酒店服务员态度可亲，早餐可以在两个餐厅吃，缓解早餐排队的压力。行', '在花园连住四晚，酒店服务员态度可亲，早餐可以在两个餐厅吃，缓解早餐排队的压力。行政酒廊的早餐有点差强人意。', '2024-01-31', 4, '[''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234r12000d3de951C537_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000d3dhfowD071_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000d3dgzfk7DD8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '特别好，房间很干净，而且很大，位置方便，旁边就有地铁5号线，周围有饭店可以喝早茶', '特别好，房间很干净，而且很大，位置方便，旁边就有地铁5号线，周围有饭店可以喝早茶，棒棒哒', '2024-02-17', 5, '[''卫生状况'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0234612000d87hlhb1936_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '行政酒廊很赞，特别感谢小云安排好位置 和热牛奶。早餐时的种类 环境也非常好。', '行政酒廊很赞，特别感谢小云安排好位置 和热牛奶。早餐时的种类 环境也非常好。', '2024-05-09', 5, '[''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234m12000dxf5lj0D060_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234d12000dxf095s61E3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000dxezcwhCAE6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '地理位置很优越，不过酒店外围在施工，影响不太大。入住的速度还可以。整体的体验满意', '地理位置很优越，不过酒店外围在施工，影响不太大。入住的速度还可以。整体的体验满意，住的套房，房间很大很舒服，还有餐饮券去荔湾亭用晚饭了，两人套餐女生也可以吃的非常饱了。', '2023-12-11', 5, '[''整体满意度'', ''交通便利性'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0230b12000cprm4bh06FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000cprkqb9093F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000cprl49435DA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000cprba0u1311_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000cprigewA552_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000cprg56n9D11_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000cprjyks139F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间非常好，就是缺少浴缸…可惜碰到泳池维修没办法游泳，自助早餐挺好的，两个餐厅都', '房间非常好，就是缺少浴缸…可惜碰到泳池维修没办法游泳，自助早餐挺好的，两个餐厅都可以用餐～小朋友还可以喂鱼，服务员也很友好', '2024-01-16', 5, '[''房间设施'', ''公共设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236g12000cyaifbbF609_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000cyajivz86CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000cyais6d0920_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店值得打卡，订的木棉双床，前台把房间升级到了粤韵，还送了康乃馨花，小小惊喜', '花园酒店值得打卡，订的木棉双床，前台把房间升级到了粤韵，还送了康乃馨花，小小惊喜。酒店服务好，硬件好，景色美，文化底蕴深厚，就是早餐相对普通了', '2024-01-02', 5, '[''整体满意度'', ''前台服务'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0230c12000cukqqgqE022_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000cukhaqe352D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000cuklajiAF17_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000cukhpql5016_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000cukh1dx2113_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：一家38年历史的酒店，也是广州的本土品牌。性价比非常高。', '环境：一家38年历史的酒店，也是广州的本土品牌。性价比非常高。

设施：健身房24h，游泳池，后花园，大瀑布。

卫生：干净整洁

服务：因为生日，特意给我房间布置了，晚上回到酒店还准备了惊喜，有一个小蛋糕。真的很贴心。
并且客户说的都有认真的来回馈。', '2023-11-21', 5, '[''性价比'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234h12000cm29mv3DBA0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231112000cm25wefAA78_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000cm22onmC24A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000cm2433oB00A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000cm22og9CE58_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000cm25pmq2B1D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000cm22ontC0BB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台S小姐姐（忘了英文名了，只记得首字母是S）给免费升级到了套房，虽位于闹市，但', '前台S小姐姐（忘了英文名了，只记得首字母是S）给免费升级到了套房，虽位于闹市，但房间很安静，干净整洁，书桌上放的旅游咨讯很有帮助。冲凉房的淋浴头用起来很舒服，床和被子睡着也很舒适，尤其是枕头，我是很挑枕头的，这个枕头一百分。早晨拉开窗帘，看见“小蛮腰”，美好的一天。', '2023-11-19', 5, '[''房间设施'', ''安静程度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236a12000clnp6xl7BF5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000clnk5h0A959_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000clnlze7765E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000clno2ybD50C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店特别好，里面有个花园，可以带宝贝去喂喂鱼，逛逛花园，去北京路和码头都不远，我', '酒店特别好，里面有个花园，可以带宝贝去喂喂鱼，逛逛花园，去北京路和码头都不远，我们都是打车前往', '2024-02-10', 5, '[''周边配套'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0234a12000d683gnoA8AA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：优美', '环境：优美
设施：高档

服务：贴心', '2024-04-06', 5, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231012000dlpwjl41C41_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000dlq7j38C535_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000dlq7wjrF1FA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000dlq6c5q1613_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b12000dlq0dbn91EB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '进酒店就觉得舒服', '进酒店就觉得舒服', '2024-04-29', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234m12000dtionge4C1F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000dtiodpn4E46_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务、环境还是保持了一定的水准，家人都比较满意。酒店内的博物馆也让人印象深刻，一', '服务、环境还是保持了一定的水准，家人都比较满意。酒店内的博物馆也让人印象深刻，一次愉快的广州之旅。', '2024-02-06', 4, '[''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236n12000d55woo1835F_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235412000d55x0wg4FAE_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234512000d55w8b6023E_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次过年在广州花园酒店，很棒的一次旅行，服务态度非常好，什么是宾至如归，算是在这', '这次过年在广州花园酒店，很棒的一次旅行，服务态度非常好，什么是宾至如归，算是在这里体验到了', '2024-02-12', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230912000d6szjpq47AC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意，出行之前看有些人说这个酒店太老了，推荐你们住什么四季，还有广州塔对面的', '非常满意，出行之前看有些人说这个酒店太老了，推荐你们住什么四季，还有广州塔对面的那些酒店，其实没有很大用处，花园酒店毕竟是广州第一个国际酒店，不管是内饰还是整体都是很值得看一看，住一下，这次买了活动套餐。有行政走廊用餐，下午茶和晚餐小吃，在30楼，可以看风景喝点小酒，非常好，套餐还包括酒店人员带着介绍整个酒店的打卡点，可以让你完整的知道从酒店申请，到酒店部分风水细节，让你会有不一样的体验，没有这介绍可能很多细节都不会注意到，酒店整天服务很好，每一层会有专人在电梯口，早餐很丰富，很推荐住', '2023-11-17', 5, '[''整体满意度'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231412000clabutg5E01_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000cladvyx670D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233h12000cla8h8q8DC1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000clafxip9664_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境古色古香，大堂金碧辉煌', '环境古色古香，大堂金碧辉煌', '2024-04-12', 4, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230b12000dnr5fg98B0E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净整洁舒适', '房间干净整洁舒适', '2024-04-26', 5, '[''卫生状况'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230212000dsi0fwuF2BB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000dshsf0o5781_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务很好。老牌五星酒店，半数服务员都是外籍的，为了方便全球各地的游客，这个细节很', '服务很好。老牌五星酒店，半数服务员都是外籍的，为了方便全球各地的游客，这个细节很好??卫生和设施也都很好，虽然外观看着旧了一些，但内部装修非常好，以后还会再入住！', '2024-01-09', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231112000cw6rv1t326E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000cw6rsxg03DD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000cw6n38hB37D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000cw6sng801A0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '无论停车、服务、设施还是环境，各方面都OK的五星级酒店，送了花水果饮料，尤其是那', '无论停车、服务、设施还是环境，各方面都OK的五星级酒店，送了花水果饮料，尤其是那个花园，早晨起来逛逛太美了，真是超级喜欢和享受的一天哦。', '2024-01-02', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234l12000culilcbE741_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000culxrerD200_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000culo0laCBB8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000culz1daBA50_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间是发霉的，关于房间的其它就不想多说了！服务态度谈吐有点崇洋媚外的感觉，而且退', '房间是发霉的，关于房间的其它就不想多说了！服务态度谈吐有点崇洋媚外的感觉，而且退房时的前台接待自我感觉莫名其妙的良好，一副不耐烦的样子！唯一值得表扬一点，地铁交通是便利的！', '2023-12-04', 2, '[''房间设施'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0236912000coeho8w5508_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000coebvmk36AC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e12000coei3ap5DCA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000coed8t6547C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店名不虚传，宽敞的大堂，有瀑布的大花园，内容丰富的博物馆，无处不在的美丽鲜', '花园酒店名不虚传，宽敞的大堂，有瀑布的大花园，内容丰富的博物馆，无处不在的美丽鲜花，还有贴心的服务，让人宾至如归，下次再来??', '2024-01-07', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233912000cvrxj57ABC9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000cvrxjskD92F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000cvrxhc5C5AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236u12000cvrxj5vC382_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '工作人员都很热情，Marry还帮我们布置了纪念日房间，服务态度非常好??', '工作人员都很热情，Marry还帮我们布置了纪念日房间，服务态度非常好??
房间干净明亮，高楼层很安静
酒店博物馆也很有意思
可惜没时间逛后花园', '2024-09-15', 5, '[''前台服务'', ''卫生状况'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232l12000fkqrvos164C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '携程活动时囤的券，非常划算。酒店景观很棒，入住时庆生，升级了房型。升级后的房型蛮', '携程活动时囤的券，非常划算。酒店景观很棒，入住时庆生，升级了房型。升级后的房型蛮大，做了生日布置，满意。checkin时等待时间有点长，还好我们有行政酒廊待遇，就先上去喝下午茶了。整体服务还不错，特别是行政酒廊的小姐姐，服务非常好，还记住我们喝的饮料。第二天恰逢周末，早餐大排长队，无奈只能打包回房间吃，这点看评论酒店一直有这个问题，希望能改善。', '2023-11-22', 4, '[''性价比'', ''景观/朝向'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0236a12000cm6itmp1F11_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000cm6f71u3824_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000cm6cyo465E4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236y12000cm6b41v959A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '自助早餐真的很一般 品种非常少 花园很美 大堂装饰的也很有新年气氛 服务也不错', '自助早餐真的很一般 品种非常少 花园很美 大堂装饰的也很有新年气氛 服务也不错', '2024-02-17', 4, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232f12000d8ay4xg67B9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不喜欢老酒店，虽然房间是最近翻新过的，但是满足父母情怀之后以后不会再选择啦。酒店', '不喜欢老酒店，虽然房间是最近翻新过的，但是满足父母情怀之后以后不会再选择啦。酒店其实不小，但是人很多，很吵。', '2024-04-06', 3, '[''安静程度'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235g12000dln5gij0924_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000dln2lfd426B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000dlmzhge2542_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) 