/dimg04.c-ctrip.com/images/0231b12000civaunm2DFF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234g12000civdeqj3D40_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大环境不错，交通便利，酒店对面有商场，也可以逛逛。房间挺大，但是有些老旧，晚', '酒店大环境不错，交通便利，酒店对面有商场，也可以逛逛。房间挺大，但是有些老旧，晚上空调声音挺大。第一天入住送了小点心。', '2024-01-27', 4, '[''交通便利性'', ''周边配套'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234012000d1z10puD3F0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000d1ymfisE6BF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000d1yxgiaA21A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次来广州，无论是来旅游，还是再远的地方办事，都会住到花园酒店，只因喜欢，老牌五', '每次来广州，无论是来旅游，还是再远的地方办事，都会住到花园酒店，只因喜欢，老牌五星级酒店体验感超棒！', '2024-01-13', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230f12000cxhoi0uFBA3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t12000cxhkkjx8024_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000cxho0kgD58C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '百金五星不是没有道理的，文化底蕴和现代化的完美结合，床品舒适，按我家妹妹的话说：', '百金五星不是没有道理的，文化底蕴和现代化的完美结合，床品舒适，按我家妹妹的话说：睡在云朵里！服务也是白金五星，加床的工作人员在看到我们带着两个孩子，主动拿来了儿童用品，又加多了两只水，很暖心??参加了酒店打卡活动，再一次认识到花园酒店的魅力，美丽的鲜花、弥漫在空气中的香薰、友善的笑容和服务，搭配合理的灯光，给客人带来非常好的心情，可惜天气冷没有去游泳，如果还没有恒温游泳池就太好了??♀?', '2023-10-23', 5, '[''整体满意度'', ''房间设施'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232012000cfsfdtiC4B1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000cfshrus1626_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000cfsis1e1A1D_R_150_150_R5_Q70_D.jpg\", \"h